import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SafeCommandExecution {

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a website to ping: ");
        String input = br.readLine();

        // Sanitize the user input by only allowing alphanumeric characters and dots
        if (!input.matches("[a-zA-Z0-9.]+")) {
            System.err.println("Invalid input. Only alphanumeric characters and dots are allowed.");
            return;
        }

        // Execute the ping command safely by passing arguments separately
        String[] command = {"ping", input};

        Process process = Runtime.getRuntime().exec(command);
        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

